import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface SpeedImpact {
  downloadSpeed: number;
  uploadSpeed: number;
  latencyIncrease: number;
}

interface VpnStatusData {
  connectionStatus: string;
  serverLocation: string;
  speedImpact: SpeedImpact;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const vpnData = response.data as VpnStatusData;
  const metaData = response.meta as MetaData;

  const isConnected = vpnData.connectionStatus === 'Connected';

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 300,
        maxWidth: 400,
        bgcolor: '#ECEFF1',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body1" sx={{ color: metaData.primaryColor, fontWeight: 600 }}>
              SecureNet VPN
            </Typography>
            <Typography variant="h6" sx={{ color: isConnected ? '#4CAF50' : '#F44336', mb: 0.5 }}>
              {vpnData.connectionStatus}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Server Location: {vpnData.serverLocation}
            </Typography>
          </Box>

          <Stack direction="row" spacing={2}>
            <Chip
              icon={vpnData.speedImpact.downloadSpeed >= 0 ? <TrendingUp /> : <TrendingDown />}
              label={`Download: ${vpnData.speedImpact.downloadSpeed} Mbps`}
              sx={{ bgcolor: '#D1C4E9', color: '#311B92', fontSize: '11px' }}
            />
            <Chip
              icon={vpnData.speedImpact.uploadSpeed >= 0 ? <TrendingUp /> : <TrendingDown />}
              label={`Upload: ${vpnData.speedImpact.uploadSpeed} Mbps`}
              sx={{ bgcolor: '#BBDEFB', color: '#0D47A1', fontSize: '11px' }}
            />
          </Stack>

          <Box>
            <Typography variant="caption" color="text.secondary">
              Latency Increase: {vpnData.speedImpact.latencyIncrease} ms
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
